  "code": "def topological_sort(dependencies):
    graph = {}
    in_degree = {}

    # Build the graph and calculate in-degrees
    for task, dependencies in dependencies.items():
        graph[task] = dependencies
        for dependency in dependencies:
            if dependency not in in_degree:
                in_degree[dependency] = 0
            in_degree[dependency] += 1

    # Perform DFS to detect cycles
    visited = set()
    def dfs(task):
        if task in visited:
            return False
        visited.add(task)
        for dependency in graph.get(task, []):
            if not dfs(dependency):
                return False
        visited.remove(task)
        return True

    # Find the root tasks (tasks with no incoming edges)
    root_tasks = [task for task, degree in in_degree.items() if degree == 0]

    # Perform DFS on each root task to find a valid order
    order = []
    while root_tasks:
        task = root_tasks.pop(0)
        order.append(task)
        for dependency in graph.get(task, []):
            in_degree[dependency] -= 1
            if in_degree[dependency] == 0:
                root_tasks.append(dependency)

    # Check for cycles
    if len(order) != len(dependencies):
        return 'Error: Cycle detected in the dependency graph. Cannot topologically sort tasks.'

    return order",
