  "code": "def topological_sort(dependencies):\n    # Create an empty dictionary to store the in-degree of each task\n    indegree = {task: 0 for task in dependencies}\n    # Create a list to store the sorted tasks\n    sorted_tasks = []\n    # Use a set to keep track of visited tasks\n    visited = set()\n    # Find all tasks with an in-degree of zero and add them to the queue\n    queue = [task for task, degree in indegree.items() if degree == 0]\n    while queue:\n        current_task = queue.pop(0)\n        sorted_tasks.append(current_task)\n        # Decrease the in-degree of all neighboring tasks by one\n        for neighbor in dependencies[current_task]:\n            indegree[neighbor] -= 1\n            if indegree[neighbor] == 0:\n                queue.append(neighbor)\n    # If there are any tasks left in the queue, a cycle exists\n    if len(queue) > 0:\n        return 'Error: Cycle detected in task dependencies'\n    return sorted_tasks",
