  "task_summary": "Chunk a long text into pieces of at most N characters without breaking words",
  "approach": "Iterate through the text, keeping track of the current chunk and the remaining characters to be processed.",
  "code": "def chunk_text(text, n):\n    chunks = []\n    start = 0\n    while start < len(text):\n        end = min(start + n, len(text))\n        if ' ' in text[start:end]:\n            # Find the last space before the current chunk boundary\n            last_space = text.rfind(' ', start, end)\n            chunks.append(text[start:last_space])\n            start = last_space + 1\n        else:\n            chunks.append(text[start:end])\n            start = end\n    return chunks",
  "complexity": {
