  "task_summary": "Chunk a long text into pieces of at most N characters without breaking words when possible",
  "approach": "Iterate through the text, keeping track of the current chunk and the start index.",
  "code": "def chunk_text(text, n):
    chunks = []
    start = 0
    while start < len(text):
        end = min(start + n, len(text))
        if ' ' in text[start:end]:
            # Break at the first whitespace found within the chunk
            end = text.find(' ', start)
        else:
            # No space found, continue until the next N characters
            while end < len(text) and text[end] != ' ':
                end += 1
        chunks.append(text[start:end])
        start = end
    return chunks",
