  "code": "def deduplicate_customers(records):
    if not records: return {}

    # Initialize an empty dictionary to store the latest record for each email.
    customer_dict = {}

    for record in records:
        # Extract the email from the record.
        email = record['email']

        # Check if the email already exists in the dictionary.
        if email in customer_dict:
            # Update the timestamp of the existing record if it is older than the current one.
            if customer_dict[email]['timestamp'] < record['timestamp']:
                customer_dict[email] = {'timestamp': record['timestamp'], 'details': record}
