        self.name = name
        self.last_contacted = last_contacted

    def __repr__(self):
        return f'Customer(email={self.email}, name={self.name}, last_contacted={self.last_contacted})'

def deduplicate_customers(customers):
    customer_dict = {}
    for customer in customers:
        if customer.email not in customer_dict or customer.last_contacted > customer_dict[customer.email].last_contacted:
            customer_dict[customer.email] = customer
    return list(customer_dict.values())

