  "code": "```python
def min_edit_distance(s1, s2):
    m, n = len(s1), len(s2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    # Fill the DP table
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i - 1] == s2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]
            else:
                dp[i][j] = min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]) + 1

    # Reconstruct the optimal edit sequence
    i, j = m, n
    edits = []
    while i > 0 and j > 0:
        if s1[i - 1] == s2[j - 1]:
            edits.append('D')  # Delete
            i -= 1
            j -= 1
        elif dp[i - 1][j] < dp[i][j - 1]:
            edits.append('I')  # Insert
            i -= 1
        else:
            edits.append('S')  # Substitute
            j -= 1

    while i > 0:
        edits.append('D')  # Delete
        i -= 1

    while j > 0:
        edits.append('I')  # Insert
        j -= 1

    return dp[m][n], ''.join(reversed(edits))
