{
  "task_summary": "Given two strings, compute their minimum edit distance using dynamic programming and construct an optimal edit sequence.",
  "approach": "Utilize a nested loop to fill a matrix with the edit distances between substrings of the input strings and construct the sequence by backtracking from the bottom-right corner of the matrix.",
  "code": "
# Import necessary packages
from typing import List, Tuple

# Function to compute the minimum edit distance between two strings
def min_edit_distance(s1: str, s2: str) -> Tuple[int, List[Tuple[str, str]]]:
    # Initialize matrices
    m, n = len(s1), len(s2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    edit_sequence = [[''] * (n + 1) for _ in range(m + 1)]

    # Fill the dp matrix with minimum edit distances
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i - 1] == s2[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]
                edit_sequence[i][j] = edit_sequence[i - 1][j - 1] + ('=' if i > 0 and j > 0 else '')
            else:
                min_cost = [dp[i-1][j], dp[i][j-1]]
                min_index = 0
                for k in range(2):
                    if min_cost[k] == min(min_cost):
                        min_index = k
                dp[i][j] = min_cost[min_index] + 1
                edit_sequence[i][j] = 'X' * len(edit_sequence[i - 1][j]) + s1[i-1]
                if min_index == 0:
                    edit_sequence[i][j] += 'U' * len(edit_sequence[i][j-1])
                else:
                    edit_sequence[i][j] += 'R' * len(edit_sequence[i - 1][j])

    # Reconstruct the optimal edit sequence from the dp matrix
    i, j = m, n
    seq = []
    while i > 0 or j > 0:
        if s1[i-1] == s2[j-1]:
            seq.append(('=' if i > 0 and j > 0 else ''))
            i -= 1
            j -= 1
        elif dp[i-1][j] < dp[i][j-1]:
            seq.append('U' * len(edit_sequence[i][j-1]))
            i -= 1
        else:
            seq.append('R' * len(edit_sequence[i-1][j]))
            j -= 1
    return dp[m][n], reversed(seq)

