  "task_summary": "Detecting Cycles in Wait-for Graph",
  "approach": "Depth-First Search (DFS) with Backtracking",
  "code": "```python
def detect_cycle(graph, start_node=None):
    visited = set()
    path = []

    def dfs(node):
        nonlocal visited, path
        if node in visited:
            return True
        visited.add(node)
        path.append(node)

        for neighbor in graph[node]:
            if dfs(neighbor):
                return True

        path.pop()
        return False

    if start_node is None:
        start_node = next(iter(graph))

    return dfs(start_node) or path
