  "task_summary": "Generate SQL statements for a normalized schema from a denormalized export",
  "approach": "Read the denormalized data, identify relationships, and generate SQL statements to normalize it",
  "code": "```python
def generate_sql_statements(denormalized_data):
    # Read the denormalized data
    table_names = set()
    for row in denormalized_data:
        table_names.add(row['table_name'])

    # Identify relationships
    relationships = {}
    for row in denormalized_data:
        if row['parent_table'] and row['child_table']:
            if row['parent_table'] not in relationships:
                relationships[row['parent_table']] = set()
            relationships[row['parent_table']].add(row['child_table'])

    # Generate SQL statements
    sql_statements = []
    for table_name, columns in denormalized_data.items():
        if table_name not in relationships:
            continue

        primary_key = None
        foreign_keys = {}
        for column in columns:
            if column['is_primary_key']:
                primary_key = column['column_name']
            elif column['is_foreign_key']:
                foreign_keys[column['column_name']] = {'table': column['parent_table'], 'column': column['child_column']}

        # Generate the CREATE TABLE statement
        create_table_statement = f"CREATE TABLE {table_name} (
    primary key ({primary_key})
"
        sql_statements.append(create_table_statement)

        # Generate the INSERT INTO statements
        for row in denormalized_data[table_name]:
            values = [row[column['column_name']] for column in columns if not column['is_primary_key']]
            insert_statement = f"INSERT INTO {table_name} ({', '.join(values)}) VALUES ({', '.join(['?'] * len(values))})"
            sql_statements.append(insert_statement)

        # Generate the FOREIGN KEY statements
        for foreign_key, details in foreign_keys.items():
            parent_table = details['table']
            child_column = details['column']
            foreign_key_statement = f"ALTER TABLE {table_name} ADD CONSTRAINT fk_{foreign_key} FOREIGN KEY ({foreign_key}) REFERENCES {parent_table}({child_column})"
            sql_statements.append(foreign_key_statement)

    return sql_statements
