import os
from datetime import datetime
from collections import defaultdict

def analyze_log_files(log_directory, time_window):
    # Initialize data structures to store logs and their components
    logs = defaultdict(list)
    component_logs = defaultdict(list)
    repeated_failures = defaultdict(set)
    failure_counts = defaultdict(int)
    last_failure_time = defaultdict(datetime)

    # Iterate over log files in the directory
    for filename in os.listdir(log_directory):
        if filename.endswith('.log'):
            file_path = os.path.join(log_directory, filename)
            with open(file_path, 'r') as file:
                lines = file.readlines()
                for line in lines:
                    # Parse error message from log line
                    try:
                        component, error_message = parse_error_line(line)
                    except ValueError:
                        continue

                    # Add log to logs dictionary
                    logs[file_path].append(error_message)

                    # Group logs by component
                    if component not in component_logs:
                        component_logs[component] = logs[file_path]
                    else:
                        component_logs[component].extend(logs[file_path])

    # Detect repeated failures within a time window
    for component, logs in component_logs.items():
        for i in range(len(logs) - 1):
            if logs[i] == logs[i + 1]:
                last_failure_time[component] = min(last_failure_time[component], datetime.now())
                repeated_failures[component].add(logs[i])

    # Generate summary statistics and sample lines
    summary_stats = defaultdict(dict)
    for component, logs in component_logs.items():
        if len(repeated_failures[component]) > 0:
            summary_stats[component]['repeated_failures'] = repeated_failures[component]
        else:
            summary_stats[component]['no_repeated_failures'] = True
        summary_stats[component]['total_errors'] = len(logs)
        summary_stats[component]['sample_lines'] = logs[:10]

    return summary_stats

def parse_error_line(line):
    # Parse error message from log line
    try:
        component, error_message = line.split(' - ', 1)
    except ValueError:
        raise ValueError(f'Invalid log format: {line}')
    return component, error_message
