import { PriorityQueue } from 'pqueuejs';

interface Job {
  id: number;
  priority: number;
  task: () => Promise<void>;
  retryLimit: number;
  failureCallback: (error: Error) => void;
}

class JobScheduler {
  private queue = new PriorityQueue<number, Job>({ comparator: (a, b) => a.priority - b.priority });
  private runningJobs: Set<number> = new Set<number>();

  constructor(private maxConcurrency: number) {}

  addJob(job: Job): void {
    this.queue.push(job.id, job);
  }

  async run(): Promise<void> {
    while (this.queue.size() > 0 && this.runningJobs.size() < this.maxConcurrency) {
      const jobId = this.queue.pop() as number;
      const job = this.queue.get(jobId)!;

      if (!job.retryLimit || job.retryLimit > 0) {
        try {
          await job.task();
          this.runningJobs.delete(jobId);
        } catch (error) {
          job.failureCallback(error);
          if (job.retryLimit && job.retryLimit > 0) {
            job.retryLimit -= 1;
            this.queue.push(job.id, job);
          }
        }
      } else {
        this.queue.remove(jobId);
      }
    }
  }
}

// Example usage:
const scheduler = new JobScheduler(3);
scheduler.addJob({
  id: 1,
  priority: 2,
  task: async () => console.log('Task 1 completed'),
  retryLimit: 3,
  failureCallback: (error) => console.error(`Error in Task 1: ${error.message}`)
});
scheduler.addJob({
  id: 2,
  priority: 1,
