{
  "task_summary": "Implements a lightweight job scheduler with priorities, retry limits, and failure callbacks",
  "approach": "Utilizes a simple array to maintain sorted tasks based on their priority. Uses recursion to handle task execution and retries.",
  "code": "```typescript
const PriorityQueue = require('fastpriorityqueue').PriorityQueue;

class JobScheduler {
  constructor() {
    this.queue = new PriorityQueue({ comparator: (a, b) => a.priority - b.priority });
    this.nextJobID = 0;
    this.retryCount = 0;
  }

  addJob(priority, fn, options = {}) {
    const jobID = ++this.nextJobID;
    const task = { id: jobID, priority, fn, ...options, retryCount: 0 };
    this.queue.push(task);
  }

  async executeNextJob() {
    while (!this.queue.isEmpty()) {
      const task = this.queue.pop();
      if (task.retryCount < options.retryLimit) {
        try {
          await task.fn(task.id);
          console.log(`Task ${task.id} completed successfully`);
          break;
        } catch (error) {
          console.error(`Task ${task.id} failed with error:`, error);
          task.retryCount += 1;
          if (task.retryCount < options.retryLimit) {
            this.queue.push(task);
          } else {
            console.error(`Task ${task.id} failed too many times`);
          }
        }
      } else {
        console.error(`Task ${task.id} failed permanently`);
      }
    }
  }

  async schedule() {
    while (true) {
      await this.executeNextJob();
      // Wait for a short period before checking again if there are new jobs to execute
      await new Promise(resolve => setTimeout(resolve, 1000));
    }
  }
}

class RetryCallback {
  constructor(options = {}) {
    this.count = 0;
  }

  increment() {
    this.count += 1;
  }

  reset() {
    this.count = 0;
  }

  reachedLimit() {
    return this.count >= options.retryLimit;
  }
}
