class Customer:
    def __init__(self, name, email, phone_number, country_code):
        self.name = name
        self.email = email
        self.phone_number = phone_number
        self.country_code = country_code

    def normalize_name(self):
        # Normalize the name by removing special characters and converting to lowercase
        return ''.join(filter(str.isalnum, self.name)).lower()

    def normalize_email(self):
        # Normalize the email by removing special characters and converting to lowercase
        return ''.join(filter(str.isalnum, self.email)).lower()

    def normalize_phone_number(self):
        # Normalize the phone number by removing special characters and converting to lowercase
        return ''.join(filter(str.isdigit, self.phone_number)).lower()

    def normalize_country_code(self):
        # Normalize the country code by removing special characters and converting to lowercase
        return ''.join(filter(str.isalnum, self.country_code)).lower()

    def __str__(self):
        return f'Customer(name={self.name}, email={self.email}, phone_number={self.phone_number}, country_code={self.country_code})'

class CustomerTransformer:
    def transform(self, records):
        transformed_records = []
        for record in records:
            customer = Customer(*record)
            normalized_customer = Customer(
                name=customer.normalize_name(),
                email=customer.normalize_email(),
                phone_number=customer.normalize_phone_number(),
                country_code=customer.normalize_country_code()
            )
            transformed_records.append(normalized_customer)
        return transformed_records

# Example usage:
customers = [
    ('John Doe', 'john.doe@example.com', '123-456-7890', '+1'),
    ('Jane Smith', 'jane.smith@sample.org', '987-654-3210', '+1'),
    ('Alice Johnson', 'alice.johnson@example.net', '555-123-4567', '+1'),
]
transformer = CustomerTransformer()
transformed_customers = transformer.transform(customers)
for customer in transformed_customers:
    print(customer)
