class CustomerNormalizer:
    def __init__(self):
        self.errors = []

    def normalize(self, record):
        normalized_record = {
            'name': self.normalize_name(record.get('name', '')),
            'email': self.normalize_email(record.get('email', '')),
            'phone_number': self.normalize_phone_number(record.get('phone_number', '')),
            'country_code': self.normalize_country_code(record.get('country_code', ''))
        }

        # Track errors during normalization
        if not normalized_record['name']:
            self.errors.append('Name is missing or incorrect. Expected format: First Last')
        if not normalized_record['email']:
            self.errors.append('Email is missing or incorrect. Expected format: username@domain.com')
        if not normalized_record['phone_number']:
            self.errors.append('Phone number is missing or incorrect. Expected format: +1-234-5678900')
        if not normalized_record['country_code']:
            self.errors.append('Country code is missing or incorrect. Expected format: ISO 3166 alpha-2 code')

        return normalized_record,

    def normalize_name(self, name):
        # Normalize name by trimming spaces and converting to lowercase
        if not name.strip():
            return ''
        return name.lower().strip()

    def normalize_email(self, email):
        # Normalize email by removing special characters and splitting it into username and domain
        cleaned_email = ''.join(char for char in email if char.isalnum() or char.isspace())
        parts = cleaned_email.split('@')
        if len(parts) != 2:
            return ''
        username, domain = parts
        # Normalize username by removing special characters and splitting it into parts
        username_parts = ''.join(char for char in username if char.isalnum() or char.isspace())
        if len(username_parts) == 0:
            return ''
        normalized_username = username_parts.lower().strip()
        # Return the normalized email with username and domain combined
        return f'{normalized_username}@{domain}

    def normalize_phone_number(self, phone_number):
        # Normalize phone number by removing special characters and stripping it
        cleaned_phone_number = ''.join(char for char in phone_number if char.isalnum() or char.isspace())
        # Check if the phone number starts with a valid country code prefix
        if not cleaned_phone_number.startswith('+1-'):
            return ''
        # Normalize phone number by removing leading '+1-' and splitting it into area code, exchange, and subscriber ID
        parts = cleaned_phone_number[3:].split('-')
        if len(parts) != 3:
            return ''
        normalized_area_code = parts[0]
        normalized_exchange = parts[1]
        normalized_subscriber_id = parts[2]
        # Return the normalized phone number with country code, exchange, and subscriber ID combined
        return f'+{normalized_country_code}-{normalized_exchange}-{normalized_subscriber_id}

    def normalize_country_code(self, country_code):
        # Normalize country code by removing special characters and stripping it
        cleaned_country_code = ''.join(char for char in country_code if char.isalnum() or char.isspace())
        # Check if the country code is a valid ISO 3166 alpha-2 code
        iso_3166_codes = {'US', 'CA', 'MX', 'IN'}
        if cleaned_country_code not in iso_3166_codes:
            return ''
        # Return the normalized country code with leading '+1-' and splitting it into alpha-2 and alpha-3 codes
        parts = cleaned_country_code.split('-')
        if len(parts) != 2:
            return ''
        normalized_alpha_2_code = parts[0]
        normalized_alpha_3_code = parts[1]
        # Return the normalized country code with leading '+1-' and splitting it into alpha-2 and alpha-3 codes
        return f'+{normalized_alpha_2_code}-{normalized_alpha_3_code}
