  "code": "```
class ProjectAnalyzer {
  constructor(files) {
    this.files = files;
    this.analyzeFiles();
  }

  analyzeFiles() {
    const fileTypes = new Map();
    let largestFiles = [];
    let secretExposures = [];
    let unreadableFiles = [];

    for (const file of this.files) {
      const fileType = file.type;
      if (!fileTypes.has(fileType)) {
        fileTypes.set(fileType, 0);
      }
      fileTypes.set(fileType, fileTypes.get(fileType) + file.size);

      if (file.size > largestFiles.length || !largestFiles.length) {
        largestFiles.push(file);
      }

      // Simulate potential secret exposures and unreadable files based on the file type
      switch (fileType) {
        case 'script.js':
          // Check for secret exposure in script.js files
          if (file.contents.includes('secretKey')) {
            secretExposures.push(file);
          }
          break;
        case 'image.png':
          // Simulate unreadable file condition based on image size
          if (file.size > 10MB) {
            unreadableFiles.push(file);
          }
          break;
        default:
          break;
      }
    }

    this.result = {
      fileTypeSummary: JSON.stringify(Array.from(fileTypes.entries(), ([type, size]) => ({ type, size })) || 'No files found', null, 2),
      largestFilesSummary: JSON.stringify(largestFiles.slice(0, 5), null, 2) || 'No large files found',
      secretExposuresSummary: JSON.stringify(secretExposures.slice(0, 3), null, 2) || 'No potential secret exposures found',
      unreadableFilesSummary: JSON.stringify(unreadableFiles.slice(0, 2), null, 2) || 'No unreadable files found'
    };
  }

  get result() {
    return this._result;
  }
}
