import json
from typing import List, Dict

def validate_api_payloads(payloads: List[Dict[str, any]]) -> List[Dict[str, str]]:
    results = []
    for payload in payloads:
        try:
            # Apply validation rules here
            if not all(key in payload for key in ['id', 'title', 'description']):
                errors = {'payload': json.dumps(payload), 'error': 'Invalid payload format. Missing required fields.'}
                results.append(errors)
            else:
                results.append({'payload': json.dumps(payload), 'error': ''})
        except Exception as e:
            error = f'Error processing payload: {str(e)}'
            results.append({'payload': json.dumps(payload), 'error': error})
    return results
